"use client";

import * as React from "react";

import { cn } from "@/lib/utils";

import { AssigneeChip } from "./parts/assignee-chip";
import { ClaimButton } from "./parts/claim-button";
import { OpenForAnyoneToggle } from "./parts/open-for-anyone-toggle";
import { resolveMember } from "./lib/members";
import { resolveTaskChoiceState } from "./lib/state";
import type { TaskChoiceControlProps } from "./types";

/**
 * The single-unit assembly — a **logic-free fan-out**. It resolves the three-
 * state slice once (`resolveTaskChoiceState`, exported) and renders the relevant
 * flat sub-parts for that state, passing each only what it needs. It owns **no**
 * state (the picker-open flag lives in `AssigneeChip`); a hand-assembly using
 * the resolver + parts behaves identically. **No `Root`, no context** (D-06 —
 * nothing cross-cutting to hold).
 *
 * Autonomy affordance (E4): choice is always available, never forced;
 * release/reassign never penalizes the prior assignee (§6). Telemetry fires on
 * meaningful committed interactions only (§8.3).
 */
export function TaskChoiceControl01({
  teamId,
  members,
  value,
  currentMemberId,
  onOpenForAnyoneChange,
  onClaim,
  onAssigneeChange,
  onEvent,
  readOnly = false,
  density = "comfortable",
  labels,
  className,
  "aria-label": ariaLabel,
}: TaskChoiceControlProps) {
  const state = resolveTaskChoiceState(value);

  const emit = React.useCallback(() => {
    onEvent?.({ type: "task-choice.interaction", teamId, taskId: value.taskId });
  }, [onEvent, teamId, value.taskId]);

  // Wrap the host callbacks so telemetry fires after a committed interaction.
  // An omitted base callback ⇒ omitted wrapper ⇒ the affordance capability-gates off.
  const handleOpenChange = onOpenForAnyoneChange
    ? (open: boolean) => {
        onOpenForAnyoneChange(open);
        emit();
      }
    : undefined;

  const handleClaim = onClaim
    ? (memberId: string) => {
        onClaim(memberId);
        emit();
      }
    : undefined;

  const handleAssigneeChange = onAssigneeChange
    ? (memberId: string | undefined) => {
        onAssigneeChange(memberId);
        emit();
      }
    : undefined;

  // Neutral state sentence for the polite live region (never a negative frame).
  const assignee = resolveMember(value.assigneeId, members);
  const stateSentence =
    state === "claimed"
      ? `Assigned to ${assignee?.displayName ?? value.assigneeId ?? "a teammate"}`
      : state === "open"
        ? "Open for anyone"
        : "Unassigned";

  return (
    <div
      role="group"
      aria-label={ariaLabel ?? "Task assignment choice"}
      className={cn(
        "reveal-up flex flex-wrap items-center gap-x-3 gap-y-2",
        density === "compact" ? "text-xs" : "text-sm",
        className,
      )}
    >
      {/* The open-flag is always renderable (stays visible + toggleable in "claimed"). */}
      <OpenForAnyoneToggle
        open={value.openForAnyone}
        onOpenChange={handleOpenChange}
        label={labels?.openForAnyone}
        readOnly={readOnly}
        density={density}
      />

      {state === "claimed" ? (
        <AssigneeChip
          value={value}
          members={members}
          onAssigneeChange={handleAssigneeChange}
          readOnly={readOnly}
          density={density}
          releaseLabel={labels?.release}
          reassignLabel={labels?.reassign}
        />
      ) : (
        <ClaimButton
          memberId={currentMemberId}
          onClaim={handleClaim}
          label={labels?.claim}
          readOnly={readOnly}
          density={density}
        />
      )}

      <span aria-live="polite" className="sr-only">
        {stateSentence}
      </span>
    </div>
  );
}

// Assembly — the logic-free fan-out (single-unit; no Root/context).
export { TaskChoiceControl01 } from "./task-choice-control-01";

// Flat à-la-carte sub-parts (each mountable alone).
export { OpenForAnyoneToggle } from "./parts/open-for-anyone-toggle";
export { ClaimButton } from "./parts/claim-button";
export { AssigneeChip } from "./parts/assignee-chip";

// Pure helpers (a hand-assembly resolves identically).
export { resolveTaskChoiceState } from "./lib/state";
export { resolveMember, initialsFor } from "./lib/members";

// Public types.
export type {
  TaskChoiceState,
  TeamMember,
  TaskChoiceRenderState,
  TaskChoiceInteraction,
  TaskChoiceEvent,
  TaskChoiceDensity,
  TaskChoiceLabels,
  TaskChoiceControlProps,
  OpenForAnyoneToggleProps,
  ClaimButtonProps,
  AssigneeChipProps,
} from "./types";

/**
 * `task-choice-control-01` — public type surface.
 *
 * Framework-free (no `"use client"`). Per system D-03 the domain slice is
 * **re-declared locally** — this component imports nothing from another registry
 * component (the `gamification-system` §4 model is the source of truth these are
 * copied from, byte-faithful, not imported). The autonomy affordance is generic
 * *over the host's task* only in that it consumes a slice, never a full task —
 * no `<T>` generic (that re-arms the generic-over-host-task drift risk).
 */

/** The choice slice for ONE task (system §4). Controlled (D-06). */
export interface TaskChoiceState {
  taskId: string;
  /** Open for anyone on the team to pick up. */
  openForAnyone: boolean;
  /** Assigned member id; `undefined` → unassigned. */
  assigneeId?: string;
}

/** A team member — identity only (avatar resolution + the reassign picker). */
export type TeamMember = {
  id: string;
  displayName: string;
  avatarUrl?: string;
};

/** The deterministic resolved render state (see `lib/state.ts`). */
export type TaskChoiceRenderState = "open" | "claimed" | "unassigned";

/**
 * Internal interaction discriminant → feeds `onEvent`. Kept internal (not a
 * public callback arg); the public telemetry event is intentionally coarse.
 */
export type TaskChoiceInteraction =
  | { kind: "open-toggled"; open: boolean }
  | { kind: "claimed"; memberId: string }
  | { kind: "reassigned"; memberId?: string }; // undefined = released

/** The public telemetry event (system §6 / D-07 — exact union member). */
export type TaskChoiceEvent = {
  type: "task-choice.interaction";
  teamId: string;
  taskId: string;
};

/** Layout density — fits a kanban card vs a rich-card row. */
export type TaskChoiceDensity = "compact" | "comfortable";

/** Per-state copy overrides (D8 — one button, overridable). */
export interface TaskChoiceLabels {
  claim?: string; // default "I'll take this"
  openForAnyone?: string; // default "Open for anyone"
  release?: string; // default "Release"
  reassign?: string; // default "Reassign…"
}

/** Props for the assembly `TaskChoiceControl01`. */
export interface TaskChoiceControlProps {
  /**
   * Identity + telemetry scope (D-15: a scalar `teamId`, NOT a team object —
   * this component renders NO team-identity text).
   */
  teamId: string;
  /** This team's members — avatar resolution + the reassign picker (D-08). */
  members: TeamMember[];
  /** The choice slice for ONE task. Controlled (D-06). */
  value: TaskChoiceState;
  /** The viewer — default subject of "I'll take this". */
  currentMemberId?: string;

  // Change callbacks — each optional → omit ⇒ that affordance hides.
  onOpenForAnyoneChange?: (open: boolean) => void;
  /** Volunteer / claim. `memberId` defaults to `currentMemberId` upstream. */
  onClaim?: (memberId: string) => void;
  /** Reassign; pass `undefined` to RELEASE (folded in — no separate onRelease, D10). Never penalizes the prior assignee. */
  onAssigneeChange?: (memberId: string | undefined) => void;

  /** Telemetry (D-07) — `{ type:"task-choice.interaction"; teamId; taskId }` on meaningful interactions only. */
  onEvent?: (event: TaskChoiceEvent) => void;

  /** Display-only: shows state, hides ALL actions. Default `false` — choice is the default. */
  readOnly?: boolean;
  /** Density. Default `"comfortable"`. */
  density?: TaskChoiceDensity;
  /** Per-state label overrides. */
  labels?: TaskChoiceLabels;

  className?: string;
  "aria-label"?: string;
}

/** Props for the à-la-carte `OpenForAnyoneToggle` sub-part. */
export interface OpenForAnyoneToggleProps {
  open: boolean;
  onOpenChange?: (open: boolean) => void;
  label?: string;
  readOnly?: boolean;
  density?: TaskChoiceDensity;
  className?: string;
}

/** Props for the à-la-carte `ClaimButton` sub-part. */
export interface ClaimButtonProps {
  /** The member who would claim; defaults to `currentMemberId` at the assembly. */
  memberId?: string;
  onClaim?: (memberId: string) => void;
  label?: string;
  readOnly?: boolean;
  density?: TaskChoiceDensity;
  className?: string;
}

/** Props for the à-la-carte `AssigneeChip` sub-part. */
export interface AssigneeChipProps {
  value: TaskChoiceState;
  members: TeamMember[];
  onAssigneeChange?: (memberId: string | undefined) => void;
  readOnly?: boolean;
  density?: TaskChoiceDensity;
  releaseLabel?: string;
  reassignLabel?: string;
  className?: string;
}

import type { TaskChoiceRenderState, TaskChoiceState } from "../types";

/**
 * The deterministic state resolver (description §4 table). Pure, framework-free,
 * SSR-safe, test-ready. Exported so a hand-assembly resolves identically to the
 * `TaskChoiceControl01` assembly — a kit-extraction candidate (system §7.3).
 */
export function resolveTaskChoiceState(
  v: TaskChoiceState,
): TaskChoiceRenderState {
  // "claimed" wins — covers the legal `openForAnyone && assigneeId` edge.
  if (v.assigneeId != null) return "claimed";
  return v.openForAnyone ? "open" : "unassigned";
}

// Note: the open-flag is always renderable (even in "claimed" it stays visible +
// toggleable) — enforced directly in the assembly, which always mounts the toggle.

import type { TeamMember } from "../types";

/**
 * Member resolution — pure, framework-free, SSR-safe. A stale `assigneeId` not
 * present in `members` returns `undefined` (the chip degrades gracefully to
 * id-initials, never crashes — §9).
 */
export function resolveMember(
  id: string | undefined,
  members: TeamMember[],
): TeamMember | undefined {
  return id == null ? undefined : members.find((m) => m.id === id);
}

/**
 * Deterministic (SSR-safe) initials for an avatar fallback — from the member's
 * display name, or the raw id when the member is unknown (stale-id path).
 */
export function initialsFor(
  member: TeamMember | undefined,
  fallbackId: string,
): string {
  const src = (member?.displayName ?? fallbackId).trim();
  if (src === "") return "?";
  const parts = src.split(/\s+/).filter(Boolean);
  if (parts.length >= 2) {
    return (parts[0]![0]! + parts[parts.length - 1]![0]!).toUpperCase();
  }
  return src.slice(0, 2).toUpperCase();
}

"use client";

import * as React from "react";

import { Switch } from "@/components/ui/switch";
import { cn } from "@/lib/utils";

import type { OpenForAnyoneToggleProps } from "../types";

/**
 * À-la-carte sub-part — the "open for anyone" on/off control. A `Switch` reads
 * as a *setting*, which is exactly what "open for anyone" is. The label is a
 * **friendly invite, never a warning** (D9): signal-lime accent when on, never a
 * red/alert treatment — releasing a task into "open for anyone" reads as
 * generosity. Capability-gated: no `onOpenChange` (or `readOnly`) → the switch
 * is non-interactive (display-only), no dead affordance.
 */
export function OpenForAnyoneToggle({
  open,
  onOpenChange,
  label = "Open for anyone",
  readOnly = false,
  density = "comfortable",
  className,
}: OpenForAnyoneToggleProps) {
  const id = React.useId();
  const interactive = !readOnly && typeof onOpenChange === "function";

  return (
    <div className={cn("flex items-center gap-2", className)}>
      <Switch
        id={id}
        checked={open}
        onCheckedChange={interactive ? onOpenChange : undefined}
        disabled={!interactive}
        size={density === "compact" ? "sm" : "default"}
        aria-label={label}
      />
      <label
        htmlFor={id}
        className={cn(
          "flex select-none items-center gap-1",
          density === "compact" ? "text-xs" : "text-sm",
          open ? "font-medium text-foreground" : "text-muted-foreground",
          interactive && "cursor-pointer",
        )}
      >
        <span aria-hidden>🙌</span> {label}
      </label>
    </div>
  );
}

"use client";

import * as React from "react";
import { Hand } from "lucide-react";

import { Button } from "@/components/ui/button";
import { cn } from "@/lib/utils";

import type { ClaimButtonProps } from "../types";

/**
 * À-la-carte sub-part — the "I'll take this" volunteer/claim action. Warm,
 * volitional, autonomy-flavored (D8). Capability-gated: no `onClaim` (or
 * `readOnly`) → renders nothing (no dead button). If there is no `memberId` to
 * claim as (no viewer supplied), the click is a guarded no-op — the button
 * still renders so the affordance is discoverable, but the host must supply a
 * subject (documented in the guide).
 */
export function ClaimButton({
  memberId,
  onClaim,
  label = "I'll take this",
  readOnly = false,
  density = "comfortable",
  className,
}: ClaimButtonProps) {
  if (readOnly || typeof onClaim !== "function") return null;

  const compact = density === "compact";

  return (
    <Button
      type="button"
      size={compact ? "icon" : "sm"}
      variant="default"
      aria-label={label}
      title={compact ? label : undefined}
      onClick={() => {
        if (memberId != null) onClaim(memberId);
      }}
      className={cn(compact && "size-8", className)}
    >
      <Hand aria-hidden />
      {compact ? null : label}
    </Button>
  );
}

"use client";

import * as React from "react";
import { Check, UserRoundPlus } from "lucide-react";

import { Avatar, AvatarFallback, AvatarImage } from "@/components/ui/avatar";
import { Button } from "@/components/ui/button";
import {
  Command,
  CommandEmpty,
  CommandGroup,
  CommandInput,
  CommandItem,
  CommandList,
} from "@/components/ui/command";
import {
  Popover,
  PopoverContent,
  PopoverTrigger,
} from "@/components/ui/popover";
import { cn } from "@/lib/utils";

import { initialsFor, resolveMember } from "../lib/members";
import type { AssigneeChipProps } from "../types";

/**
 * À-la-carte sub-part — the assignee chip (avatar + name) with a **neutral**
 * Release + a reassign picker. The no-penalty core (§6): Release is a
 * `variant="ghost"` muted action reading "Release" — **never** destructive/red,
 * **never** "Drop"/"Abandon", **never** a penalty glyph or motion. The prior
 * assignee is never named in a negative frame. A stale `assigneeId` (not in
 * `members`) degrades to id-initials, no crash. The picker is `popover` +
 * `command` (searchable, keyboard-nav, team-scoped) — `PopoverTrigger` is used
 * directly (no `asChild`) to stay clear of the Radix↔Base-UI divergence class.
 */
export function AssigneeChip({
  value,
  members,
  onAssigneeChange,
  readOnly = false,
  density = "comfortable",
  releaseLabel = "Release",
  reassignLabel = "Reassign…",
  className,
}: AssigneeChipProps) {
  const [pickerOpen, setPickerOpen] = React.useState(false);

  const assigneeId = value.assigneeId;
  const member = resolveMember(assigneeId, members);
  const displayName = member?.displayName ?? assigneeId ?? "Unassigned";
  const interactive = !readOnly && typeof onAssigneeChange === "function";
  const compact = density === "compact";

  return (
    <div className={cn("flex items-center gap-2", className)}>
      <div className="flex min-w-0 items-center gap-2">
        <Avatar size={compact ? "sm" : "default"}>
          {member?.avatarUrl ? (
            <AvatarImage src={member.avatarUrl} alt="" />
          ) : null}
          <AvatarFallback>
            {initialsFor(member, assigneeId ?? "?")}
          </AvatarFallback>
        </Avatar>
        <span
          title={displayName}
          className={cn(
            "truncate text-foreground",
            compact ? "max-w-24 text-xs" : "text-sm",
          )}
        >
          {/* SR-readable, neutral framing — never "X dropped this". */}
          <span className="sr-only">Assigned to </span>
          {displayName}
        </span>
      </div>

      {interactive ? (
        <div className="flex items-center gap-1">
          <Popover open={pickerOpen} onOpenChange={setPickerOpen}>
            <PopoverTrigger
              aria-label={reassignLabel}
              title={reassignLabel}
              className={cn(
                "inline-flex size-8 items-center justify-center rounded-md text-muted-foreground",
                "hover:bg-muted hover:text-foreground",
                "focus-visible:ring-2 focus-visible:ring-ring focus-visible:outline-none",
              )}
            >
              <UserRoundPlus className="size-4" aria-hidden />
            </PopoverTrigger>
            <PopoverContent align="end" className="w-56 p-0">
              <Command>
                <CommandInput placeholder="Reassign to…" />
                <CommandList>
                  <CommandEmpty>No teammates to assign.</CommandEmpty>
                  <CommandGroup>
                    {members.map((m) => (
                      <CommandItem
                        key={m.id}
                        value={m.displayName}
                        onSelect={() => {
                          onAssigneeChange?.(m.id);
                          setPickerOpen(false);
                        }}
                      >
                        <Avatar size="sm">
                          {m.avatarUrl ? (
                            <AvatarImage src={m.avatarUrl} alt="" />
                          ) : null}
                          <AvatarFallback>
                            {initialsFor(m, m.id)}
                          </AvatarFallback>
                        </Avatar>
                        <span className="flex-1 truncate">{m.displayName}</span>
                        {m.id === assigneeId ? (
                          <Check className="size-4" aria-hidden />
                        ) : null}
                      </CommandItem>
                    ))}
                  </CommandGroup>
                </CommandList>
              </Command>
            </PopoverContent>
          </Popover>

          {/* Neutral, no-penalty release — folds into onAssigneeChange(undefined). */}
          <Button
            type="button"
            size="sm"
            variant="ghost"
            className="text-muted-foreground"
            onClick={() => onAssigneeChange?.(undefined)}
          >
            {releaseLabel}
          </Button>
        </div>
      ) : null}
    </div>
  );
}
